SELECT company_id AS companyId, company_name AS companyName, business_no AS businessNo, ceo_name AS ceoName, phone, email, status, created_at AS createdAt FROM tb_company WHERE company_type = 'BUYER'
AND (company_name LIKE CONCAT('%', #{searchKeyword}, '%') OR business_no LIKE CONCAT('%', #{searchKeyword}, '%'))
ORDER BY created_at DESC LIMIT #{recordCountPerPage} OFFSET #{firstIndex}
